import { Row, Text, Grid, Button } from "@nextui-org/react";
import React from "react";
import ProjectCard from "../Components/ProjectCard";

export default function AwardsSection(props: any) {
  return (
    <section id="skills">
      <Row justify="center" align="center" css={{ mt: "80px" }}>
        <Text h6>Some More Things</Text>
      </Row>
      <Row justify="center" align="center">
        <Text
          h5
          css={{
            textGradient: "45deg, $pink600 -20%, $purple600 100%",
          }}
          weight="bold"
        >
          I'd like to share
        </Text>
      </Row>
      <Grid xs={12} sm={4}>
        <InfoCard ic={1} subtitle="2+ Years" title="Experience" />
      </Grid>
      <Grid xs={12} sm={4}>
        <InfoCard ic={2} subtitle="8+ Worldwide" title="Clients" />
      </Grid>
      <Grid xs={12} sm={4}>
        <InfoCard ic={3} subtitle="23+ Completed" title="Projects" />
      </Grid>
    </section>
  );
}
